    def distance_metric(from_pos, to_pos):
        return np.linalg.norm(from_pos - to_pos)

    # Dynamic re-planning with other truck's position
    dynamic_zones = {}
    for i, pos in enumerate(all_truck_pos):
        dynamic_zones[i] = {'position': pos, 'occupied': False}

    # Calculate distances to all unvisited customers from the current truck position
    distances = [distance_metric(cur_truck_pos, customer_pos) for customer_pos in unvisited_customers]

    # Find the nearest unvisited customers based on distances and time windows
    min_score = float('inf')
    best_node = None
    for idx, dist in enumerate(distances):
        time_to_reach = dist / truck_speed
        projected_arrival = current_time + time_to_reach
        window_start, window_end = time_windows[idx]

        if projected_arrival > window_end:
            continue  # Skip if the truck cannot reach within the customer's time window

